            )
            VALUES ($1, $2, $3, $4, $5, $6, $7)
            "#,
        )
        .bind(&mt.mt_id)
        .bind(&mt.wp_id)
        .bind(&mt.name)
        .bind(micro_task_status_str(mt.status))

